script.inlineScript:
import { readFileSync, writeFileSync } from 'fs';

const input = JSON.parse(readFileSync('/output/input.json', 'utf8'));
const title = input.steps?.['submit-request']?.title || 'unknown';
const priority = input.steps?.['submit-request']?.priority || 'unknown';

writeFileSync('/output/result.json', JSON.stringify({
  processed: true,
  route: 'fast-track',
  summary: `Request "${title}" (${priority}) auto-processed via fast track.`
}));
